from flask import Flask, request, jsonify
import time
from prometheus_client import Counter, Histogram, Gauge, generate_latest, CONTENT_TYPE_LATEST
from functools import wraps
import secrets

app = Flask(__name__)

METRICS_TOKEN = secrets.token_urlsafe(32)

request_count = Counter(
    'http_requests_total',
    'Total HTTP requests',
    ['method', 'endpoint', 'status']
)

request_duration = Histogram(
    'http_request_duration_seconds',
    'HTTP request duration in seconds',
    ['method', 'endpoint']
)

active_requests = Gauge(
    'http_requests_active',
    'Number of active HTTP requests'
)

def require_metrics_auth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('X-Metrics-Token')
        if not auth_header or not secrets.compare_digest(auth_header, METRICS_TOKEN):
            return jsonify({'error': 'Unauthorized'}), 401
        return f(*args, **kwargs)
    return decorated_function

@app.before_request
def before_request():
    request.start_time = time.time()
    active_requests.inc()

@app.after_request
def after_request(response):
    active_requests.dec()
    
    if request.endpoint and request.endpoint != 'metrics':
        request_duration.labels(
            method=request.method,
            endpoint=request.endpoint
        ).observe(time.time() - request.start_time)
        
        request_count.labels(
            method=request.method,
            endpoint=request.endpoint,
            status=response.status_code
        ).inc()
    
    return response

@app.route('/metrics')
@require_metrics_auth
def metrics():
    return generate_latest(), 200, {'Content-Type': CONTENT_TYPE_LATEST}

